using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class ModelTests
{
    #region Person.FullName Tests

    [TestMethod]
    [DataRow("Smith", "John", "Smith, John", DisplayName = "Standard names")]
    [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
    [DataRow("Li", "X", "Li, X", DisplayName = "Short names")]
    public void Person_FullName_ReturnsConcatenatedLastAndFirst(string lastName, string firstName, string expected)
    {
        // Arrange - use Student as concrete implementation of abstract Person
        var student = new Student { LastName = lastName, FirstMidName = firstName };

        // Act
        var result = student.FullName;

        // Assert
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void Instructor_FullName_ReturnsCorrectFormat()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "Abercrombie",
            FirstMidName = "Kim"
        };

        // Act & Assert
        Assert.AreEqual("Abercrombie, Kim", instructor.FullName);
    }

    #endregion

    #region ErrorViewModel Tests

    [TestMethod]
    [DataRow(null, false, DisplayName = "Null RequestId")]
    [DataRow("", false, DisplayName = "Empty RequestId")]
    [DataRow("abc123", true, DisplayName = "Non-empty RequestId")]
    public void ErrorViewModel_ShowRequestId_ReflectsRequestIdState(string requestId, bool expected)
    {
        // Arrange
        var model = new ErrorViewModel { RequestId = requestId };

        // Act & Assert
        Assert.AreEqual(expected, model.ShowRequestId);
    }

    #endregion

    #region Student Model Tests

    [TestMethod]
    public void Student_InheritsFromPerson()
    {
        // Arrange & Act
        var student = new Student();

        // Assert
        Assert.IsInstanceOfType<Person>(student);
    }

    [TestMethod]
    public void Student_PropertiesSetCorrectly()
    {
        // Arrange
        var enrollmentDate = new DateTime(2023, 9, 1);
        var student = new Student
        {
            ID = 1,
            LastName = "Alexander",
            FirstMidName = "Carson",
            EnrollmentDate = enrollmentDate
        };

        // Assert
        Assert.AreEqual(1, student.ID);
        Assert.AreEqual("Alexander", student.LastName);
        Assert.AreEqual("Carson", student.FirstMidName);
        Assert.AreEqual(enrollmentDate, student.EnrollmentDate);
    }

    [TestMethod]
    public void Student_Enrollments_CanBeInitialized()
    {
        // Arrange
        var student = new Student
        {
            Enrollments = new List<Enrollment>
            {
                new Enrollment { EnrollmentID = 1, CourseID = 100 },
                new Enrollment { EnrollmentID = 2, CourseID = 200 }
            }
        };

        // Assert
        Assert.AreEqual(2, student.Enrollments.Count);
    }

    #endregion

    #region Instructor Model Tests

    [TestMethod]
    public void Instructor_InheritsFromPerson()
    {
        // Arrange & Act
        var instructor = new Instructor();

        // Assert
        Assert.IsInstanceOfType<Person>(instructor);
    }

    [TestMethod]
    public void Instructor_PropertiesSetCorrectly()
    {
        // Arrange
        var hireDate = new DateTime(1995, 3, 11);
        var instructor = new Instructor
        {
            ID = 5,
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = hireDate
        };

        // Assert
        Assert.AreEqual(5, instructor.ID);
        Assert.AreEqual("Fakhouri", instructor.LastName);
        Assert.AreEqual("Fadi", instructor.FirstMidName);
        Assert.AreEqual(hireDate, instructor.HireDate);
    }

    [TestMethod]
    public void Instructor_CourseAssignments_CanBeInitialized()
    {
        // Arrange
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 1050, InstructorID = 1 },
                new CourseAssignment { CourseID = 2021, InstructorID = 1 }
            }
        };

        // Assert
        Assert.AreEqual(2, instructor.CourseAssignments.Count);
    }

    [TestMethod]
    public void Instructor_OfficeAssignment_CanBeSet()
    {
        // Arrange
        var instructor = new Instructor
        {
            ID = 1,
            OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Smith 17" }
        };

        // Assert
        Assert.AreEqual("Smith 17", instructor.OfficeAssignment.Location);
    }

    #endregion

    #region Course Model Tests

    [TestMethod]
    public void Course_PropertiesSetCorrectly()
    {
        // Arrange
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/Uploads/image.jpg"
        };

        // Assert
        Assert.AreEqual(1050, course.CourseID);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
        Assert.AreEqual("/Uploads/image.jpg", course.TeachingMaterialImagePath);
    }

    [TestMethod]
    public void Course_NavigationProperties_CanBeSet()
    {
        // Arrange
        var course = new Course
