using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    #region Constructor Tests

    [TestMethod]
    public void Constructor_SetsPageIndexCorrectly()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 5);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 5, 2, DisplayName = "10 items, pageSize 5 = 2 pages")]
    [DataRow(11, 5, 3, DisplayName = "11 items, pageSize 5 = 3 pages (ceiling)")]
    [DataRow(0, 5, 0, DisplayName = "0 items = 0 pages")]
    [DataRow(1, 5, 1, DisplayName = "1 item, pageSize 5 = 1 page")]
    [DataRow(5, 5, 1, DisplayName = "5 items, pageSize 5 = 1 page")]
    [DataRow(100, 10, 10, DisplayName = "100 items, pageSize 10 = 10 pages")]
    [DataRow(7, 3, 3, DisplayName = "7 items, pageSize 3 = 3 pages (ceiling)")]
    public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 10, 1, 5);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("a", list[0]);
        Assert.AreEqual("b", list[1]);
        Assert.AreEqual("c", list[2]);
    }

    #endregion

    #region HasPreviousPage Tests

    [TestMethod]
    [DataRow(1, false, DisplayName = "Page 1 has no previous")]
    [DataRow(2, true, DisplayName = "Page 2 has previous")]
    [DataRow(5, true, DisplayName = "Page 5 has previous")]
    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), 50, pageIndex, 10);

        // Act & Assert
        Assert.AreEqual(expected, list.HasPreviousPage);
    }

    #endregion

    #region HasNextPage Tests

    [TestMethod]
    [DataRow(1, 10, 5, true, DisplayName = "Page 1 of 2 has next")]
    [DataRow(2, 10, 5, false, DisplayName = "Page 2 of 2 (last page) has no next")]
    [DataRow(1, 5, 5, false, DisplayName = "Page 1 of 1 (single page) has no next")]
    [DataRow(3, 50, 10, true, DisplayName = "Page 3 of 5 has next")]
    [DataRow(5, 50, 10, false, DisplayName = "Page 5 of 5 (last page) has no next")]
    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalCount, int pageSize, bool expected)
    {
        // Arrange
        var list = new PaginatedList<int>(new List<int>(), totalCount, pageIndex, pageSize);

        // Act & Assert
        Assert.AreEqual(expected, list.HasNextPage);
    }

    #endregion

    #region Create Tests

    [TestMethod]
    public void Create_ReturnsCorrectPageOfItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert - page 2 should have items 11-20
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(20, result[9]);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert - last page with 5 remaining items
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
        Assert.IsFalse(result.HasNextPage);
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_SingleItem_ReturnsOnePageWithOneItem()
    {
        // Arrange
        var source = new[] { 42 }.AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(42, result[0]);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_PageSizeEqualsItemCount_ReturnsSinglePage()
    {
        // Arrange
        var source = Enumerable.Range(1, 10).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    #endregion
}

