using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from the static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut?.Dispose();
    }

    #region SendNotification Tests

    [TestMethod]
    public void SendNotification_WithDisplayName_CreatesNotificationWithCorrectMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", "John Smith", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student 'John Smith' has been created", notification.Message);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "1050", EntityOperation.UPDATE, "System");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course (ID: 1050) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "1", "Engineering", EntityOperation.DELETE, null);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NoUserNameParameter_DefaultsToSystem()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Student 'Test' has been created", DisplayName = "CREATE message")]
    [DataRow(EntityOperation.UPDATE, "Student 'Test' has been updated", DisplayName = "UPDATE message")]
    [DataRow(EntityOperation.DELETE, "Student 'Test' has been deleted", DisplayName = "DELETE message")]
    public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "Test", operation, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        // Assert
        var after = DateTime.Now;
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void SendNotification_SetsOperationString()
    {
        // Act
        _sut.SendNotification("Instructor", "5", "Kim", EntityOperation.UPDATE, "System");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("UPDATE", notification.Operation);
    }

    #endregion

    #region ReceiveNotification Tests

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        // Arrange
        _sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        // Act & Assert - messages come out in order
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("A", first.EntityType);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("B", second.EntityType);

        var third = _sut.ReceiveNotification();
        Assert.AreEqual("C", third.EntityType);

        // Queue is now empty
        Assert.IsNull(_sut.ReceiveNotification());
    }

    [TestMethod]
    public void ReceiveNotification_RemovesMessageFromQueue()
    {
        // Arrange
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Act
        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(first);
        Assert.IsNull(second);
    }

    #endregion

    #region MarkAsRead Tests

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op for in-memory implementation
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(0);
        _sut.MarkAsRead(-1);
        _sut.MarkAsRead(int.MaxValue);
    }

    #endregion

    #region Dispose Tests

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
        // Calling Dispose again should not throw
        service.Dispose();
    }

    #endregion

    #region Queue Capacity Tests

    [TestMethod]
    public void SendNotification_ExceedsMaxQueueLength_OldMessagesDropped()
    {
        // Arrange - send more than max queue length (500)
        for (int i = 0; i < 510; i++)
        {
            _sut.SendNotification("Type", i.ToString(), $"Item{i}", EntityOperation.CREATE);
        }

        // Act - receive all available notifications
        int count = 0;
        while (_sut.ReceiveNotification() != null)
        {
            count++;
        }

        // Assert - should have at most 500 messages (some early ones dropped)
        Assert.IsTrue(count <= 500, $"Queue should be capped at 500 but had {count}");
    }

    #endregion

    #region Overload Tests

    [TestMethod]
    public void SendNotification_TwoParamOverload_WithoutDisplayName()
    {
        // Act - uses the overload without entityDisplayName
        _sut.SendNotification("Instructor", "7", EntityOperation.DELETE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor (ID: 7) has been deleted", notification.Message);
        Assert.AreEqual("Admin", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesId()
    {
        // Act
        _sut.SendNotification("Course", "100", "", EntityOperation.UPDATE, "User");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course (ID: 100) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithWhitespaceDisplayName_UsesId()
    {
        // Act
        _sut.SendNotification("Course", "100", "   ", EntityOperation.UPDATE, "User");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course (ID: 100) has been updated", notification.Message);
    }

    #endregion
}

