        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void About_WithStudents_ReturnsGroupedData()
    {
        // Arrange
        var date1 = new DateTime(2023, 9, 1);
        var date2 = new DateTime(2022, 9, 1);
        _context.Students.AddRange(
            new Student { FirstMidName = "Alice", LastName = "A", EnrollmentDate = date1 },
            new Student { FirstMidName = "Bob", LastName = "B", EnrollmentDate = date1 },
            new Student { FirstMidName = "Charlie", LastName = "C", EnrollmentDate = date2 }
        );
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        var group2023 = model.First(g => g.EnrollmentDate == date1);
        Assert.AreEqual(2, group2023.StudentCount);

        var group2022 = model.First(g => g.EnrollmentDate == date2);
        Assert.AreEqual(1, group2022.StudentCount);
    }

    [TestMethod]
    public void About_MultipleStudentsSameDate_CountsCorrectly()
    {
        // Arrange
        var date = new DateTime(2023, 1, 15);
        for (int i = 0; i < 5; i++)
        {
            _context.Students.Add(new Student
            {
                FirstMidName = $"Student{i}",
                LastName = $"Last{i}",
                EnrollmentDate = date
            });
        }
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        var model = result.Model as List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual(5, model[0].StudentCount);
    }
}

