using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context;
    private StudentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private Student CreateTestStudent(string firstName = "John", string lastName = "Doe", DateTime? enrollmentDate = null)
    {
        return new Student
        {
            FirstMidName = firstName,
            LastName = lastName,
            EnrollmentDate = enrollmentDate ?? new DateTime(2023, 9, 1)
        };
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2010, 9, 1) },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2013, 9, 1) },
            new Student { FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { FirstMidName = "Yan", LastName = "Li", EnrollmentDate = new DateTime(2012, 9, 1) }
        );
        _context.SaveChanges();
    }

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = CreateTestStudent();
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.Details(student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("John", model.FirstMidName);
        Assert.AreEqual("Doe", model.LastName);
    }

    #endregion

    #region Create GET Tests

    [TestMethod]
    public void Create_GET_ReturnsViewWithStudentWithTodaysDate()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    #endregion

    #region Create POST Tests

    [TestMethod]
    public void Create_POST_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = CreateTestStudent();

        // Act
        var result = _controller.Create(student);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Create_POST_ValidStudent_SavesStudentToDatabase()
    {
        // Arrange
        var student = CreateTestStudent("Jane", "Smith", new DateTime(2023, 1, 15));

        // Act
        _controller.Create(student);

        // Assert
        var saved = _context.Students.First();
        Assert.AreEqual("Jane", saved.FirstMidName);
        Assert.AreEqual("Smith", saved.LastName);
        Assert.AreEqual(new DateTime(2023, 1, 15), saved.EnrollmentDate);
    }

    [TestMethod]
    public void Create_POST_MinValueEnrollmentDate_ReturnsViewWithError()
    {
        // Arrange
        var student = CreateTestStudent();
        student.EnrollmentDate = DateTime.MinValue;

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_POST_DefaultDateTimeEnrollmentDate_ReturnsViewWithError()
    {
        // Arrange
        var student = CreateTestStudent();
        student.EnrollmentDate = default(DateTime);

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_POST_DateBefore1753_ReturnsViewWithError()
    {
        // Arrange
        var student = CreateTestStudent();
        student.EnrollmentDate = new DateTime(1752, 12, 31);

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        var student = CreateTestStudent();
        _controller.ModelState.AddModelError("LastName", "Required");

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(student, result.Model);
    }

    #endregion

    #region Edit GET Tests

    [TestMethod]
    public void Edit_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_GET_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_GET_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = CreateTestStudent();
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.Edit(student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("John", model.FirstMidName);
    }

    #endregion

    #region Edit POST Tests

    [TestMethod]
    public void Edit_POST_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = CreateTestStudent();
        _context.Students.Add(student);
        _context.SaveChanges();
        _context.Entry(student).State = EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = student.ID,
            FirstMidName = "Updated",
            LastName = "Name",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        var result = _controller.Edit(updatedStudent);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Edit_POST_MinValueDate_ReturnsViewWithError()
    {
        // Arrange
        var student = CreateTestStudent();
        student.EnrollmentDate = DateTime.MinValue;

        // Act
        var result = _controller.Edit(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Edit_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        var student = CreateTestStudent();
        _controller.ModelState.AddModelError("LastName", "Required");

        // Act
        var result = _controller.Edit(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    #endregion

    #region Delete GET Tests

    [TestMethod]
    public void Delete_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_GET_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_GET_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = CreateTestStudent();
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.Delete(student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("John", model.FirstMidName);
    }

    #endregion

    #region DeleteConfirmed Tests

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        // Arrange
        var student = CreateTestStudent();
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.DeleteConfirmed(student.ID);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
        Assert.AreEqual(0, _context.Students.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_InvalidId_RedirectsToIndexWithoutCrash()
    {
        // Act - when student is not found, it throws and is caught
        var result = _controller.DeleteConfirmed(999);

        // Assert - should redirect to Index (error is caught)
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    #endregion

    #region Index Tests

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count > 0);
        // Default sort is by LastName ascending
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_ReturnsStudentsInDescendingOrder()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Li", model[0].LastName);
    }

    [TestMethod]
    public void Index_DateSort_ReturnsStudentsOrderedByDate()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // Earliest date first
        Assert.AreEqual(new DateTime(2010, 9, 1), model[0].EnrollmentDate);
    }

    [TestMethod]
    public void Index_DateDescSort_ReturnsStudentsOrderedByDateDescending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
