using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Microsoft.EntityFrameworkCore;
using Moq;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context;
    private CoursesController _controller;
    private Mock<IWebHostEnvironment> _mockEnv;
    private Mock<ILogger<CoursesController>> _mockLogger;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _mockEnv.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _mockLogger = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private void SeedDepartment()
    {
        _context.Departments.Add(new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1)
        });
        _context.SaveChanges();
    }

    private Course CreateTestCourse(int courseId = 1050, string title = "Chemistry", int credits = 3, int departmentId = 1)
    {
        return new Course
        {
            CourseID = courseId,
            Title = title,
            Credits = credits,
            DepartmentID = departmentId
        };
    }

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsViewWithCourses()
    {
        // Arrange
        SeedDepartment();
        _context.Courses.Add(CreateTestCourse());
        _context.SaveChanges();

        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Chemistry", model[0].Title);
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Index_MultipleCourses_ReturnsAll()
    {
        // Arrange
        SeedDepartment();
        _context.Courses.AddRange(
            CreateTestCourse(1050, "Chemistry"),
            CreateTestCourse(4022, "Microeconomics"),
            CreateTestCourse(1045, "Calculus")
        );
        _context.SaveChanges();

        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        var model = result.Model as List<Course>;
        Assert.AreEqual(3, model.Count);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        _context.Courses.Add(course);
        _context.SaveChanges();

        // Act
        var result = _controller.Details(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual("Chemistry", model.Title);
        Assert.AreEqual(3, model.Credits);
    }

    #endregion

    #region Create GET Tests

    [TestMethod]
    public void Create_GET_ReturnsViewWithEmptyCourse()
    {
        // Arrange
        SeedDepartment();

        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Model);
        Assert.IsInstanceOfType<Course>(result.Model);
    }

    #endregion

    #region Create POST Tests

    [TestMethod]
    public void Create_POST_ValidCourse_NoImage_RedirectsToIndex()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();

        // Act
        var result = _controller.Create(course, null);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Create_POST_ValidCourse_SavesToDB()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse(2000, "Physics", 4, 1);

        // Act
        _controller.Create(course, null);

        // Assert
        var saved = _context.Courses.Find(2000);
        Assert.IsNotNull(saved);
        Assert.AreEqual("Physics", saved.Title);
        Assert.AreEqual(4, saved.Credits);
    }

    [TestMethod]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        _controller.ModelState.AddModelError("Title", "Required");

        // Act
        var result = _controller.Create(course, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_POST_InvalidFileExtension_ReturnsViewWithError()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("document.exe");
        mockFile.Setup(f => f.Length).Returns(1024);

        // Act
        var result = _controller.Create(course, mockFile.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        var errors = _controller.ModelState["teachingMaterialImage"].Errors;
        Assert.IsTrue(errors.Any(e => e.ErrorMessage.Contains("valid image file")));
    }

    [TestMethod]
    public void Create_POST_FileTooLarge_ReturnsViewWithError()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("large.jpg");
        mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

        // Act
        var result = _controller.Create(course, mockFile.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        var errors = _controller.ModelState["teachingMaterialImage"].Errors;
        Assert.IsTrue(errors.Any(e => e.ErrorMessage.Contains("5MB")));
    }

    [TestMethod]
    [DataRow(".exe", DisplayName = "Executable file")]
    [DataRow(".pdf", DisplayName = "PDF file")]
    [DataRow(".doc", DisplayName = "Word file")]
    [DataRow(".txt", DisplayName = "Text file")]
    public void Create_POST_InvalidExtensions_ReturnError(string extension)
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns($"file{extension}");
        mockFile.Setup(f => f.Length).Returns(1024);

        // Act
        var result = _controller.Create(course, mockFile.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    [DataRow(".jpg", DisplayName = "JPG file")]
    [DataRow(".jpeg", DisplayName = "JPEG file")]
    [DataRow(".png", DisplayName = "PNG file")]
    [DataRow(".gif", DisplayName = "GIF file")]
    [DataRow(".bmp", DisplayName = "BMP file")]
    public void Create_POST_ValidExtensions_DoNotReturnExtensionError(string extension)
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns($"image{extension}");
        mockFile.Setup(f => f.Length).Returns(1024);
        // Set up CopyTo to do nothing (simulates file write)
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        // Act
        var result = _controller.Create(course, mockFile.Object);

        // Assert - should not have extension-related error
        if (_controller.ModelState.ContainsKey("teachingMaterialImage"))
        {
            var errors = _controller.ModelState["teachingMaterialImage"].Errors;
            Assert.IsFalse(errors.Any(e => e.ErrorMessage.Contains("valid image file")),
                $"Extension {extension} should be valid");
        }
    }

    #endregion

    #region Edit GET Tests

    [TestMethod]
    public void Edit_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit((int?)null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_GET_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_GET_ValidId_ReturnsViewWithCourse()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        _context.Courses.Add(course);
        _context.SaveChanges();

        // Act
        var result = _controller.Edit(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual("Chemistry", model.Title);
    }

    #endregion

    #region Edit POST Tests

    [TestMethod]
    public void Edit_POST_ValidCourse_NoImage_RedirectsToIndex()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        _context.Courses.Add(course);
        _context.SaveChanges();
        _context.Entry(course).State = EntityState.Detached;

        var updated = CreateTestCourse(1050, "Chemistry Updated", 4, 1);

        // Act
        var result = _controller.Edit(updated, null);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Edit_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        _controller.ModelState.AddModelError("Title", "Required");

        // Act
        var result = _controller.Edit(course, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_POST_InvalidFileExtension_ReturnsViewWithError()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        _context.Courses.Add(course);
        _context.SaveChanges();
        _context.Entry(course).State = EntityState.Detached;

        var updatedCourse = CreateTestCourse();
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("document.xyz");
        mockFile.Setup(f => f.Length).Returns(1024);

        // Act
        var result = _controller.Edit(updatedCourse, mockFile.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [TestMethod]
    public void Edit_POST_FileTooLarge_ReturnsViewWithError()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        _context.Courses.Add(course);
        _context.SaveChanges();
        _context.Entry(course).State = EntityState.Detached;

        var updatedCourse = CreateTestCourse();
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("large.png");
        mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

        // Act
        var result = _controller.Edit(updatedCourse, mockFile.Object) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    #endregion

    #region Delete GET Tests

    [TestMethod]
    public void Delete_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_GET_ValidId_ReturnsViewWithCourse()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        _context.Courses.Add(course);
        _context.SaveChanges();

        // Act
        var result = _controller.Delete(1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual("Chemistry", model.Title);
    }

    #endregion

    #region DeleteConfirmed Tests

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        _context.Courses.Add(course);
        _context.SaveChanges();

        // Act
        var result = _controller.DeleteConfirmed(1050);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
        Assert.AreEqual(0, _context.Courses.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_CourseWithImage_RedirectsToIndex()
    {
        // Arrange
        SeedDepartment();
        var course = CreateTestCourse();
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test.jpg";
        _context.Courses.Add(course);
        _context.SaveChanges();

        // Act
        var result = _controller.DeleteConfirmed(1050);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    #endregion
}

