using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context;
    private InstructorsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private Instructor CreateTestInstructor(string firstName = "Kim", string lastName = "Abercrombie", DateTime? hireDate = null)
    {
        return new Instructor
        {
            FirstMidName = firstName,
            LastName = lastName,
            HireDate = hireDate ?? new DateTime(1995, 3, 11),
            CourseAssignments = new List<CourseAssignment>()
        };
    }

    private void SeedInstructorWithCourses()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = dept.DepartmentID,
            Enrollments = new List<Enrollment>()
        };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var instructor = CreateTestInstructor();
        instructor.OfficeAssignment = new OfficeAssignment { Location = "Smith 17" };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        _context.CourseAssignments.Add(new CourseAssignment
        {
            InstructorID = instructor.ID,
            CourseID = course.CourseID
        });
        _context.SaveChanges();
    }

    #region Index Tests

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        // Arrange
        SeedInstructorWithCourses();

        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Instructors.Any());
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyInstructors()
    {
        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsFalse(model.Instructors.Any());
    }

    [TestMethod]
    public void Index_WithInstructorId_SetsCourses()
    {
        // Arrange
        SeedInstructorWithCourses();
        var instructorId = _context.Instructors.First().ID;

        // Act
        var result = _controller.Index(instructorId, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.IsTrue(model.Courses.Any());
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
