    {
        // Arrange
        var dept = new Department { Name = "Test", Budget = 100000m, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1001, Title = "Course1", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 1002, Title = "Course2", Credits = 3, DepartmentID = dept.DepartmentID }
        );
        _context.SaveChanges();

        var instructor = CreateTestInstructor();
        var selectedCourses = new[] { "1001", "1002" };

        // Act
        _controller.Create(instructor, selectedCourses);

        // Assert
        var saved = _context.Instructors.Include(i => i.CourseAssignments).First();
        Assert.AreEqual(2, saved.CourseAssignments.Count);
    }

    [TestMethod]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        // Arrange
        var instructor = CreateTestInstructor();
        _controller.ModelState.AddModelError("LastName", "Required");

        // Act
        var result = _controller.Create(instructor, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    #endregion

    #region Delete GET Tests

    [TestMethod]
    public void Delete_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_GET_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_GET_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var instructor = CreateTestInstructor();
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Act
        var result = _controller.Delete(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Kim", model.FirstMidName);
    }

    #endregion

    #region DeleteConfirmed Tests

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
    {
        // Arrange
        var instructor = CreateTestInstructor();
        instructor.OfficeAssignment = new OfficeAssignment { Location = "Office 1" };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Act
        var result = _controller.DeleteConfirmed(instructor.ID);

        // Assert
        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
        Assert.AreEqual(0, _context.Instructors.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorAdministersDepartment_NullsDepartmentInstructorId()
    {
        // Arrange
        var instructor = CreateTestInstructor();
        instructor.OfficeAssignment = new OfficeAssignment { Location = "Office 1" };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var dept = new Department
        {
            Name = "Test Dept",
            Budget = 100000m,
            StartDate = DateTime.Now,
            InstructorID = instructor.ID
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        // Act
        _controller.DeleteConfirmed(instructor.ID);

        // Assert
        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.IsNull(updatedDept.InstructorID);
    }

    #endregion

    #region Edit GET Tests

    [TestMethod]
    public void Edit_GET_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit((int?)null);

        // Assert
        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_GET_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        SeedInstructorWithCourses();
        var instructorId = _context.Instructors.First().ID;

        // Act
        var result = _controller.Edit(instructorId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Kim", model.FirstMidName);
    }

    #endregion
}

