using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new NotificationsController(_context);

        // Drain the static queue before each test
        using var tempService = new NotificationService();
        while (tempService.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    #endregion

    #region GetNotifications Tests

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);
        Assert.IsNotNull(jsonResult.Value);
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsSuccessWithData()
    {
        // Arrange - enqueue a notification via the service
        using var service = new NotificationService();
        service.SendNotification("Student", "1", "John", EntityOperation.CREATE, "Admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);
        Assert.IsNotNull(jsonResult.Value);
    }

    [TestMethod]
    public void GetNotifications_MultipleNotifications_ReturnsUpTo10()
    {
        // Arrange - enqueue 15 notifications
        using var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), $"Item{i}", EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications() as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        // The controller limits to 10 notifications per call
    }

    #endregion

    #region MarkAsRead Tests

    [TestMethod]
    public void MarkAsRead_ValidId_ReturnsSuccessJson()
    {
        // Act
        var result = _controller.MarkAsRead(1) as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
    }

    [TestMethod]
    public void MarkAsRead_ZeroId_ReturnsSuccessJson()
    {
        // Act - MarkAsRead is a no-op, so any id should work
        var result = _controller.MarkAsRead(0) as JsonResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
    }

    #endregion
}

