using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class SchoolContextTests
{
    [TestMethod]
    public void SchoolContext_CanBeCreatedWithInMemory()
    {
        // Arrange & Act
        using var context = TestHelpers.CreateInMemoryContext();

        // Assert
        Assert.IsNotNull(context);
        Assert.IsNotNull(context.Students);
        Assert.IsNotNull(context.Courses);
        Assert.IsNotNull(context.Departments);
        Assert.IsNotNull(context.Instructors);
        Assert.IsNotNull(context.Enrollments);
        Assert.IsNotNull(context.OfficeAssignments);
        Assert.IsNotNull(context.CourseAssignments);
        Assert.IsNotNull(context.Notifications);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveStudent()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        context.Students.Add(student);
        context.SaveChanges();

        // Assert
        var retrieved = context.Students.First();
        Assert.AreEqual("Test", retrieved.FirstMidName);
        Assert.AreEqual("Student", retrieved.LastName);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveCourse()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = new Department { Name = "Test", Budget = 100000m, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };

        // Act
        context.Courses.Add(course);
        context.SaveChanges();

        // Assert
        var retrieved = context.Courses.Find(1050);
        Assert.IsNotNull(retrieved);
        Assert.AreEqual("Chemistry", retrieved.Title);
    }

    [TestMethod]
    public void SchoolContext_CourseAssignment_HasCompositeKey()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = new Department { Name = "Test", Budget = 100000m, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.SaveChanges();

        var instructor = new Instructor { FirstMidName = "A", LastName = "B", HireDate = DateTime.Now };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var course = new Course { CourseID = 1001, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var assignment = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };

        // Act
        context.CourseAssignments.Add(assignment);
        context.SaveChanges();

        // Assert
        var retrieved = context.CourseAssignments.Find(course.CourseID, instructor.ID);
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(instructor.ID, retrieved.InstructorID);
        Assert.AreEqual(course.CourseID, retrieved.CourseID);
    }

    [TestMethod]
    public void SchoolContext_CanAddNotification()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test message",
            CreatedAt = DateTime.Now,
            CreatedBy = "Admin",
            IsRead = false
        };

        // Act
        context.Notifications.Add(notification);
        context.SaveChanges();

        // Assert
        var retrieved = context.Notifications.First();
        Assert.AreEqual("Student", retrieved.EntityType);
        Assert.AreEqual("CREATE", retrieved.Operation);
    }

    [TestMethod]
    public void SchoolContext_SupportsTPHInheritance()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        var student = new Student { FirstMidName = "S", LastName = "Student", EnrollmentDate = DateTime.Now };
        var instructor = new Instructor { FirstMidName = "I", LastName = "Instructor", HireDate = DateTime.Now };

        // Act
        context.Students.Add(student);
        context.Instructors.Add(instructor);
        context.SaveChanges();

        // Assert - both should be accessible through People
        var allPeople = context.People.ToList();
        Assert.AreEqual(2, allPeople.Count);
        Assert.IsTrue(allPeople.Any(p => p is Student));
        Assert.IsTrue(allPeople.Any(p => p is Instructor));
    }

    [TestMethod]
    public void SchoolContext_EnrollmentRelationships()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = new Department { Name = "Test", Budget = 100000m, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.SaveChanges();

        var student = new Student { FirstMidName = "Test", LastName = "Student", EnrollmentDate = DateTime.Now };
        context.Students.Add(student);
        context.SaveChanges();

        var course = new Course { CourseID = 1001, Title = "TestCourse", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var enrollment = new Enrollment { StudentID = student.ID, CourseID = course.CourseID, Grade = Grade.A };

        // Act
        context.Enrollments.Add(enrollment);
        context.SaveChanges();

        // Assert
        var retrieved = context.Enrollments
            .Include(e => e.Student)
            .Include(e => e.Course)
            .First();
        Assert.AreEqual("Test", retrieved.Student.FirstMidName);
        Assert.AreEqual("TestCourse", retrieved.Course.Title);
        Assert.AreEqual(Grade.A, retrieved.Grade);
    }
}

